		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L),
				JoinSearchWork.unlimited(), provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		for (int occurrenceId = 0; occurrenceId < plans.size(); occurrenceId++) {
			search.seedFactor(occurrenceId,
					factorWinner(occurrenceId + 1, 10 + occurrenceId, plans.get(occurrenceId),
							PhysicalProperties.ANY),
					ProvidedPhysicalProperties.ANY);
		}
		JoinTree baseTree = JoinTree.factor(0);
		JoinTree probeTree = JoinTree.factor(1);
		JoinTree independentTree = JoinTree.factor(2);
		JoinTree independentPrefix = JoinTree.join(baseTree, independentTree);
		JoinTree forbiddenProbePrefix = JoinTree.join(probeTree, independentTree);
		search.acceptPartition(new JoinMemoExpressionCandidate("mixed-test",
				new JoinMemoExpression(Set.of(), baseTree, independentTree)));
		search.acceptPartition(new JoinMemoExpressionCandidate("mixed-test",
				new JoinMemoExpression(Set.of(), independentPrefix, probeTree)));
		search.acceptPartition(new JoinMemoExpressionCandidate("mixed-test",
				new JoinMemoExpression(Set.of(0), probeTree, independentTree)));
		search.acceptPartition(new JoinMemoExpressionCandidate("mixed-test",
				new JoinMemoExpression(Set.of(), baseTree, forbiddenProbePrefix)));

		assertTrue(search.drain());
		assertTrue(observed.contains(new ObservedTransition(baseSubset, independentSubset, null)),
				"An independent factor must remain an ordinary INNER extension");
		assertTrue(observed.contains(new ObservedTransition(baseSubset.union(independentSubset), probeSubset, 0)),
				"The directed RHS must be consumed only by its typed edge");
		assertTrue(observed.stream()
				.noneMatch(transition -> transition.edgeId() == null
						&& transition.left().union(transition.right()).contains(1)),
				"An unapplied directed RHS must never be swallowed by an ordinary join");
		List<Integer> roots = search.rootCandidateIds(Integer.MAX_VALUE);
		assertFalse(roots.isEmpty());
		for (int root : roots) {
			assertEquals(1, search.memo().candidate(root).group().appliedEdges().size(),
					"The directed edge must be part of scoped root identity exactly once");
			List<JoinRegionRecipe> recipes = search.memo().reachableRecipes(List.of(root));
			assertEquals(1L, recipes.stream().filter(JoinRegionRecipe.Join.class::isInstance).count());
			assertEquals(1L, recipes.stream().filter(JoinRegionRecipe.Edge.class::isInstance).count());
		}
