	@Test
	void typedEdgeAndPredicateFactsComposeOnceInScopedRootIdentity() {
		BindingUniverse universe = BindingUniverse.create();
		StatementPattern basePlan = pattern("shared", "baseOnly", "baseValue");
		StatementPattern probePlan = pattern("shared", "probePredicate", "probeValue");
		List<StatementPattern> plans = List.of(basePlan, probePlan);
		List<JoinFactorDescriptor> descriptors = java.util.stream.IntStream.range(0, plans.size())
				.mapToObj(occurrenceId -> {
					StatementPattern plan = plans.get(occurrenceId);
					BindingMask bindings = universe.maskOf(plan.getBindingNames());
					return new JoinFactorDescriptor(occurrenceId, 10 + occurrenceId, plan, universe, bindings,
							bindings, BindingMask.EMPTY);
				})
				.toList();
		JoinSearchContext context = new JoinSearchContext(descriptors, universe, BindingMask.EMPTY,
				PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinSubset base = JoinSubset.ofOrdinals(0);
		JoinSubset probe = JoinSubset.ofOrdinals(1);
		JoinPredicate predicate = new JoinPredicate(7, new Bound(new Var("baseOnly")), Set.of("baseOnly"),
				List.of());
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(0, 10), new JoinFactor(1, 11)),
				List.of(new JoinDependency(1, Set.of(0))), List.of(predicate),
				List.of(new JoinEdge(0, JoinEdge.Kind.ANTI, JoinEdge.Origin.NOT_EXISTS, base, probe,
						base.union(probe), Set.of())));
		AtomicInteger expressionIds = new AtomicInteger(300);
		JoinImplementationProvider.Implementation edgeImplementation = cardinalityImplementation("edge", 0.1d,
				expressionIds);
		JoinImplementationProvider provider = new JoinImplementationProvider() {
			@Override
			public List<? extends Implementation> implementations(Request request) {
				return List.of(edgeImplementation);
			}

			@Override
			public Optional<CardinalityEstimate> logicalEdgeCardinality(LogicalEdgeRequest request) {
				return Optional.of(CardinalityEstimate.estimated(50.0d, "logical-edge-and-predicate-test"));
			}

			@Override
			public List<? extends PredicateImplementation> predicateImplementations(PredicateRequest request) {
				return List.of(new PredicateImplementation() {
					@Override
					public String id() {
						return "half-selectivity-predicate";
					}

					@Override
					public Optional<Result> evaluate(PredicateRequest evaluated) {
						double rows = evaluated.input().candidate().cardinality().rows() * 0.5d;
						Filter plan = new Filter(evaluated.input().winner().plan().clone(),
								evaluated.predicate().conditionTemplate());
						return Optional.of(syntheticResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(),
								plan, rows, JoinRegionRecipe.predicate(evaluated.predicate().id())));
					}
				});
			}
		};
		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L),
				JoinSearchWork.unlimited(), provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		search.seedFactor(0, factorWinner(1, 10, basePlan, PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);
		search.seedFactor(1, factorWinner(2, 11, probePlan, PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);
		search.acceptPartition(new JoinMemoExpressionCandidate("edge-predicate-test",
				new JoinMemoExpression(Set.of(), JoinTree.factor(0), JoinTree.factor(1))));

		assertTrue(search.drain());
		List<Integer> roots = search.rootCandidateIds(Integer.MAX_VALUE);
		assertFalse(roots.isEmpty());
		for (int root : roots) {
			JoinRegionCandidate candidate = search.memo().candidate(root);
			assertEquals(1, candidate.group().appliedEdges().size());
			assertEquals(1, candidate.group().appliedPredicates().size());
			assertEquals(25.0d, candidate.cardinality().rows(), 1.0e-9d);
			List<JoinRegionRecipe> recipes = search.memo().reachableRecipes(List.of(root));
			assertEquals(1L, recipes.stream().filter(JoinRegionRecipe.Edge.class::isInstance).count());
			assertEquals(1L, recipes.stream().filter(JoinRegionRecipe.Predicate.class::isInstance).count());
		}
	}

	@Test
	void scopedLogicalStateHasOneCanonicalCardinalityAcrossPredicatePlacements() {
		AtomicInteger expressionIds = new AtomicInteger(100);
		JoinImplementationProvider provider = new JoinImplementationProvider() {
			@Override
			public List<? extends Implementation> implementations(Request request) {
				return List.of(new Implementation() {
					@Override
					public String id() {
						return "association-sensitive-join";
					}

					@Override
					public Optional<Result> evaluate(Request evaluated) {
						double rows = evaluated.left().candidate().cardinality().rows()
								* evaluated.right().candidate().cardinality().rows();
						Join plan = new Join(evaluated.left().winner().plan().clone(),
								evaluated.right().winner().plan().clone());
						return Optional.of(syntheticResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(),
								plan, rows, JoinRegionRecipe.join(evaluated.contributorId())));
					}
				});
			}

			@Override
			public List<? extends PredicateImplementation> predicateImplementations(PredicateRequest request) {
				return List.of(new PredicateImplementation() {
					@Override
					public String id() {
						return "association-sensitive-filter";
					}

					@Override
					public Optional<Result> evaluate(PredicateRequest evaluated) {
						double selectivity = evaluated.input().candidate().group().subset().size() == 1 ? 0.1d : 0.5d;
						double rows = evaluated.input().candidate().cardinality().rows() * selectivity;
						Filter plan = new Filter(evaluated.input().winner().plan().clone(),
								evaluated.predicate().conditionTemplate());
						return Optional.of(syntheticResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(),
								plan, rows, JoinRegionRecipe.predicate(evaluated.predicate().id())));
					}
				});
			}
		};
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(0, 10), new JoinFactor(1, 11)), List.of(),
				List.of(new JoinPredicate(7, new Bound(new Var("shared")), Set.of(), List.of())));
		ScopedJoinSearch search = new ScopedJoinSearch(region,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L),
				JoinSearchWork.unlimited(), provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		search.seedFactor(0, factorWinner(1, 10, pattern("a", "p1", "shared"), PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);
		search.seedFactor(1, factorWinner(2, 11, pattern("shared", "p2", "b"), PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);
		search.acceptPartition(new JoinMemoExpressionCandidate("test-contributor",
				new JoinMemoExpression(Set.of(), JoinTree.factor(0), JoinTree.factor(1))));

		assertTrue(search.drain());
		Set<Double> fullFilteredRows = java.util.stream.IntStream.range(0, search.memo().candidateCount())
				.mapToObj(search.memo()::candidate)
				.filter(candidate -> candidate.group().subset().size() == 2)
				.filter(candidate -> candidate.group().appliedPredicates().size() == 1)
				.map(candidate -> candidate.cardinality().rows())
				.collect(java.util.stream.Collectors.toUnmodifiableSet());

		assertEquals(1, fullFilteredRows.size(),
				"Association-sensitive raw estimates must collapse to one logical-state cardinality");
		assertEquals(10.0d, fullFilteredRows.iterator().next(), 1e-12,
				"The canonical state estimate must be computed in log space from factor and predicate facts");
	}

	@Test
	void sharedBindingWithoutCanonicalEvidenceDoesNotBecomeCartesianCardinality() {
		BindingUniverse universe = BindingUniverse.create();
		StatementPattern finite = pattern("finiteValue", "finitePredicate", "shared");
		StatementPattern broad = pattern("broadSubject", "broadPredicate", "shared");
		List<StatementPattern> plans = List.of(finite, broad);
		List<JoinFactorDescriptor> descriptors = java.util.stream.IntStream.range(0, plans.size())
				.mapToObj(occurrenceId -> {
					StatementPattern plan = plans.get(occurrenceId);
					BindingMask bindings = universe.maskOf(plan.getBindingNames());
					return new JoinFactorDescriptor(occurrenceId, 10 + occurrenceId, plan, universe, bindings,
							bindings, BindingMask.EMPTY);
				})
				.toList();
		JoinSearchContext context = new JoinSearchContext(descriptors, universe, BindingMask.EMPTY,
				PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(0, 10), new JoinFactor(1, 11)), List.of());
		AtomicInteger expressionIds = new AtomicInteger(100);
		JoinImplementationProvider provider = request -> List.of(new JoinImplementationProvider.Implementation() {
			@Override
			public String id() {
				return "finite-shared-lookup";
			}

			@Override
			public Optional<JoinImplementationProvider.Result> evaluate(
					JoinImplementationProvider.Request evaluated) {
				return Optional.of(syntheticResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(),
						typedEdgePlan(evaluated), 4.0d, JoinRegionRecipe.join(evaluated.contributorId())));
			}
		});
		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L),
				JoinSearchWork.unlimited(), provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		search.seedFactor(0, factorWinner(1, 10, finite, PhysicalProperties.ANY, 2.0d),
				ProvidedPhysicalProperties.ANY);
		search.seedFactor(1, factorWinner(2, 11, broad, PhysicalProperties.ANY, 45_337.0d),
				ProvidedPhysicalProperties.ANY);
		search.acceptPartition(new JoinMemoExpressionCandidate("finite-shared-test",
				new JoinMemoExpression(Set.of(), JoinTree.factor(0), JoinTree.factor(1))));

		assertTrue(search.drain());
		JoinRegionCandidate root = search.memo().candidate(search.rootCandidateIds(1).getFirst());
		assertEquals(4.0d, root.cardinality().rows(), 1.0e-12d,
				"Missing equality evidence must preserve the implementation estimate, not assume a Cartesian product");
	}

