	@Test
	void exhaustiveScopedSearchRetainsEveryAssuredPredicatePrefixLocally() {
		BindingUniverse universe = BindingUniverse.create();
		StatementPattern arm = pattern("arm", "armPredicate", "armValue");
		StatementPattern guard = pattern("guard", "guardPredicate", "guardValue");
		StatementPattern tail = pattern("tail", "tailPredicate", "tailValue");
		List<StatementPattern> plans = List.of(arm, guard, tail);
		List<JoinFactorDescriptor> descriptors = java.util.stream.IntStream.range(0, plans.size())
				.mapToObj(occurrenceId -> {
					StatementPattern plan = plans.get(occurrenceId);
					BindingMask bindings = universe.maskOf(plan.getBindingNames());
					return new JoinFactorDescriptor(occurrenceId, 10 + occurrenceId, plan, universe, bindings, bindings,
							BindingMask.EMPTY);
				})
				.toList();
		JoinSearchContext context = new JoinSearchContext(descriptors, universe, BindingMask.EMPTY,
				PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinRegion region = new JoinRegion(
				List.of(new JoinFactor(0, 10), new JoinFactor(1, 11), new JoinFactor(2, 12)), List.of(),
				List.of(new JoinPredicate(7, new Bound(new Var("arm")), Set.of("arm"), List.of())));
		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L),
				JoinSearchWork.unlimited(),
				new CascadesJoinImplementationProvider(CascadesCostModel.from(new EvaluationStatistics()), universe),
				OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		for (int occurrenceId = 0; occurrenceId < plans.size(); occurrenceId++) {
			Winner winner = factorWinner(occurrenceId + 1, 10 + occurrenceId, plans.get(occurrenceId),
					PhysicalProperties.ANY);
			search.seedFactor(occurrenceId, winner,
					TypedPhysicalPropertyBridge.provided(winner.deliveredProperties(), universe,
							winner.physicalOperatorId()));
		}
		ExhaustiveLegalJoinSearchContributor contributor = new ExhaustiveLegalJoinSearchContributor();
		contributor.contributeMemoExpressions(
				JoinSearchRequest.enumeration(region, JoinSearchRequest.Mode.COMPLETE, 0L, 0L, context),
				expression -> search.acceptPartition(new JoinMemoExpressionCandidate(
						ExhaustiveLegalJoinSearchContributor.ID, expression)));

		assertTrue(search.drain());
		Set<JoinSubset> predicateSubsets = java.util.stream.IntStream.range(0, search.memo().groupCount())
				.filter(groupId -> !search.memo().frontier(groupId).isEmpty())
				.mapToObj(search.memo()::groupKey)
				.filter(group -> group.appliedPredicates().size() == 1)
				.map(group -> group.subset())
				.collect(java.util.stream.Collectors.toUnmodifiableSet());

		assertEquals(Set.of(JoinSubset.ofOrdinals(0), JoinSubset.ofOrdinals(0, 1),
				JoinSubset.ofOrdinals(0, 2), JoinSubset.ofOrdinals(0, 1, 2)), predicateSubsets,
				"Exact scoped search must retain every local subset where the arm-bound predicate is legal");
	}

	@Test
	void predicateEligibilityIsChargedOncePerCandidateIdentityWithinOneGroup() {
		BindingUniverse universe = BindingUniverse.create();
		SearchWorkLedger work = new SearchWorkLedger(SearchLimits.EXACT);
		StatementPattern factorPlan = pattern("shared", "predicate", "value");
		BindingMask factorBindings = universe.maskOf(factorPlan.getBindingNames());
		JoinSearchContext context = new JoinSearchContext(List.of(
				new JoinFactorDescriptor(0, 10, factorPlan, universe, factorBindings, factorBindings,
						BindingMask.EMPTY)),
				universe, BindingMask.EMPTY, PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.RowGoal.ALL, JoinFactorCostModel.EstimationTier.STANDARD);
		JoinPredicate predicate = new JoinPredicate(7, new Bound(new Var("shared")), Set.of("shared"), List.of());
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(0, 10)), List.of(), List.of(predicate));
		Set<Integer> evaluatedCandidateIds = new java.util.LinkedHashSet<>();
		AtomicInteger expressionIds = new AtomicInteger(100);
		JoinImplementationProvider provider = new JoinImplementationProvider() {
			@Override
			public List<? extends Implementation> implementations(Request request) {
				return List.of();
			}

			@Override
			public List<? extends PredicateImplementation> predicateImplementations(PredicateRequest request) {
				return List.of(new PredicateImplementation() {
					@Override
					public String id() {
						return "candidate-keyed-filter";
					}

					@Override
					public Optional<Result> evaluate(PredicateRequest evaluated) {
						evaluatedCandidateIds.add(evaluated.input().candidateId());
						Filter plan = new Filter(evaluated.input().winner().plan().clone(),
								evaluated.predicate().conditionTemplate());
						return Optional.of(syntheticResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(),
								plan, 1.0d, JoinRegionRecipe.predicate(evaluated.predicate().id())));
					}
				});
			}
		};
		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L), work,
				provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		PhysicalProperties firstPath = PhysicalProperties.builder().accessPath("predicate-probe-first").build();
		PhysicalProperties secondPath = PhysicalProperties.builder().accessPath("predicate-probe-second").build();
		Winner first = factorWinner(1, 10, factorPlan, firstPath);
		Winner second = factorWinner(2, 10, factorPlan.clone(), secondPath);
		int firstCandidateId = search.seedFactor(0, first,
				TypedPhysicalPropertyBridge.provided(firstPath, universe, first.physicalOperatorId()));
		int secondCandidateId = search.seedFactor(0, second,
				TypedPhysicalPropertyBridge.provided(secondPath, universe, second.physicalOperatorId()));

		assertTrue(search.drain());
		assertEquals(Set.of(firstCandidateId, secondCandidateId), evaluatedCandidateIds);
		assertEquals(2L, work.counterSnapshot().predicateProbes(),
				"Two physical candidates in one logical group require two candidate-keyed eligibility probes");
	}

