	@Test
	void primitiveDphypPairEvaluatesBothPhysicalOrientations() {
		AtomicInteger evaluations = new AtomicInteger();
		AtomicInteger providerCalls = new AtomicInteger();
		SearchWorkLedger work = new SearchWorkLedger(SearchLimits.EXACT);
		JoinImplementationProvider provider = request -> {
			providerCalls.incrementAndGet();
			return List.of(emptyImplementation("physical", evaluations));
		};
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(10, 10), new JoinFactor(20, 11)), List.of());
		ScopedJoinSearch search = new ScopedJoinSearch(region,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.exact(100L), work,
				provider, OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		search.seedFactor(10, factorWinner(1, 10, pattern("a", "p1", "shared"), PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);
		search.seedFactor(20, factorWinner(2, 11, pattern("shared", "p2", "b"), PhysicalProperties.ANY),
				ProvidedPhysicalProperties.ANY);

		JoinSearchService.ScopedMemoTarget target = (JoinSearchService.ScopedMemoTarget) (Object) search;
		assertTrue(target.hasCandidate(1L));
		assertTrue(target.hasCandidate(2L));
		assertEquals(false, target.acceptDphypPair("dphyp", 1L, 2L));
		assertEquals(false, target.acceptDphypPair("dphyp", 1L, 2L));

		assertEquals(2, evaluations.get(),
				"A repeated CSG-CMP pair must not reevaluate either physical orientation");
		assertEquals(2, providerCalls.get(),
				"A completed candidate pair must be suppressed before rebuilding its implementation batch");
		assertEquals(2L, work.counterSnapshot().candidateEvaluations(),
				"Duplicate suppression must happen before deterministic candidate work is charged");
	}

	@Test
	void scopedJoinSearchKeepsDirectionalRequiredOuterInputStatesSeparate() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask tenant = universe.maskOf(Set.of("tenant"));
		AtomicInteger expressionIds = new AtomicInteger(100);
		JoinImplementationProvider provider = request -> List.of(new JoinImplementationProvider.Implementation() {
			@Override
			public String id() {
				return "required-outer-join";
			}

			@Override
			public Optional<JoinImplementationProvider.Result> evaluate(JoinImplementationProvider.Request evaluated) {
				boolean dependentFirst = evaluated.left().candidate().group().subset().contains(1);
				Join plan = new Join(evaluated.left().winner().plan().clone(),
						evaluated.right().winner().plan().clone());
				return Optional.of(requiredOuterResult(expressionIds.incrementAndGet(), evaluated.resultGroupId(), plan,
						dependentFirst ? 1.0d : 100.0d));
			}
		});

		ScopedJoinSearch unboundSearch = requiredOuterSearch(universe, BindingMask.EMPTY, provider);
		assertFalse(unboundSearch.acceptDphypPair("required-outer-test", 1L, 2L));
		assertTrue(unboundSearch.drain());

		JoinSubset fullSubset = JoinSubset.ofOrdinals(0, 1);
		RequiredOuterInputs tenantOuter = new RequiredOuterInputs(tenant);
		int independentGroupId = unboundSearch.memo()
				.groupIds(fullSubset, RequiredOuterInputs.NONE)
				.getFirst();
		int parameterizedGroupId = unboundSearch.memo().groupIds(fullSubset, tenantOuter).getFirst();
		assertEquals(unboundSearch.memo().groupKey(independentGroupId).subset(),
				unboundSearch.memo().groupKey(parameterizedGroupId).subset());
		assertEquals(unboundSearch.memo().groupKey(independentGroupId).appliedPredicates(),
				unboundSearch.memo().groupKey(parameterizedGroupId).appliedPredicates());

		JoinRegionCandidate independent = unboundSearch.memo().frontier(independentGroupId).getFirst();
		JoinRegionCandidate parameterized = unboundSearch.memo().frontier(parameterizedGroupId).getFirst();
		assertTrue(parameterized.cost().totalWork() < independent.cost().totalWork(),
				"The cheaper parameterized state must remain separate from the executable independent state");
		assertTrue(independent.provided().parameterBindings().isEmpty());
		assertEquals(tenant, parameterized.provided().parameterBindings());
		assertEquals(List.of(independent.id()), unboundSearch.rootCandidateIds(Integer.MAX_VALUE),
				"A later sibling may not satisfy an unresolved input required by the left prefix");

		ScopedJoinSearch boundSearch = requiredOuterSearch(universe, tenant, provider);
		assertFalse(boundSearch.acceptDphypPair("required-outer-test", 1L, 2L));
		assertTrue(boundSearch.drain());
		Set<RequiredOuterInputs> executableOuterStates = boundSearch.rootCandidateIds(Integer.MAX_VALUE)
				.stream()
				.map(boundSearch.memo()::candidate)
				.map(JoinRegionCandidate::group)
				.map(group -> group.requiredOuter())
				.collect(java.util.stream.Collectors.toUnmodifiableSet());
		assertEquals(Set.of(RequiredOuterInputs.NONE, tenantOuter), executableOuterStates,
				"Initially bound context may satisfy either retained root state");
	}

