	@Test
	void scopedHashEligibilityUsesPossibleMasksWithoutMaterializingNames() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask leftPossible = universe.maskOf(Set.of("leftOnly", "shared"));
		BindingMask rightPossible = universe.maskOf(Set.of("rightOnly", "shared"));
		BindingMask leftAssured = universe.maskOf(Set.of("leftOnly"));
		BindingMask rightAssured = universe.maskOf(Set.of("rightOnly"));
		ScopedMemoInputReference.Shape leftShape = new ScopedMemoInputReference.Shape(universe, leftPossible,
				leftAssured);
		ScopedMemoInputReference.Shape rightShape = new ScopedMemoInputReference.Shape(universe, rightPossible,
				rightAssured);
		Join join = new Join(new ScopedMemoInputReference(1, leftShape),
				new ScopedMemoInputReference(2, rightShape));
		MemoExpr expression = MemoExpr.logical(3, 12, join, List.of(10, 11), "scoped-hash-mask-test");

		assertFalse(leftAssured.intersects(rightAssured), "The shared binding must be possible but not assured");
		assertTrue(new StandardCascadesRules.HashJoinImplementationRule()
				.matches(expression, OptimizationGoal.root(), null));
		assertFalse(leftShape.hasMaterializedBindingNames());
		assertFalse(rightShape.hasMaterializedBindingNames());
	}

